import{_ as a,o as t,c as s,j as e,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"铁球回转","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/运动类/铁球回转.md","filePath":"4.资源分区/6.技艺及称号/运动类/铁球回转.md"}'),o={name:"4.资源分区/6.技艺及称号/运动类/铁球回转.md"};function d(b,r,l,_,i,c){return t(),s("div",null,[...r[0]||(r[0]=[e("h1",{id:"铁球回转",tabindex:"-1"},[p("铁球回转 "),e("a",{class:"header-anchor",href:"#铁球回转","aria-label":'Permalink to "铁球回转"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001E")])])],-1),n('<h1 id="铁球回转-1" tabindex="-1">铁球回转 <a class="header-anchor" href="#铁球回转-1" aria-label="Permalink to &quot;铁球回转&quot;">​</a></h1><p>铁球回转<br> D+500</p><p>铁球回转基本原理<br> 新世界刽子手家族齐贝林家族世代传承的秘术，将黄金回旋应用于铁球的旋转，并且以旋转的铁球投掷击打目标，旨在能够尽力地让死刑犯得以不抵抗而以最小的痛苦受刑而死。也用于齐贝林家族的表面身份——医生，借由黄金回旋带来的无限的能量，齐贝林家族得以不可思议地治疗各种各样的所谓“不愈怪病”，比如进行精细度极高的视神经缝合手术。</p><p>特制铁球<br> 50分/个<br> 这是一枚翠绿的，具有特殊花纹的金属铁球，每颗铁球的体积为1，武器伤害3L，使用铁球的攻击的检定为力量-运动-专业：铁球回转（辅助专业：力学），特制铁球还会额外再附带2点高速。</p><p>在购买铁球回转后，你便视为掌握了铁球的最基础用法，但仍然没有掌握铁球的更多用法，只会简单的进行投掷，在此时，你投掷的铁球不会自动返回手中，而是会在击中敌人后掉落，因为并未掌握黄金回转。而将黄金回转应用到铁球的投掷上则需要购买齐贝林家族的特制腰带。</p><p>齐贝林家族的特制腰带<br> 1000<br> 这是一条带着由黄金比例制成的腰带扣的腰带，占据腰带位，在没有黄金比例存在的地方，通过观察腰带扣也可以获得黄金比例。在你投掷铁球时，铁球将会在击中敌人后视同具有【回力】一般，在你的下个回合开始时自动飞回你的手中，同时，你在投掷铁球时，也可以将铁球如同具有【轻灵】一般进行投掷。腰带上还会带有存储铁球的口袋，最多能左右各悬挂一枚铁球。</p><p>学习铁球的使用：<br> 学习铁球使用的课程必须逐个购买，除第一节外，只有领悟了上一节课程后才能购买下一节。学习铁球的使用是一个循序渐进的积累过程，因此，在购买课程后，并不会立即掌握它的用法，而是在经历一场影片后领悟它的全部内容，得以正常使用。</p><p>Lesson1：别对我抱有什么奇怪的期待<br> D+500<br> 经过练习，你掌握了铁球的最基础用法，在你投掷一次铁球时，若你使用的主属性是力量，则你在铁球上获得的所有高速变为威猛，并在投掷这枚铁球时额外再获得将对方击退的效果，被攻击者使用反射豁免进行对抗伤害出目，并被击退等同于二者差值+5米的距离；若你使用的主属性是敏捷，且你增加了出手的速度，则还会再附带1点不可豁免的肢体妨碍点数。此外，你投掷铁球的高速再+1。</p><p>Lesson2：别让肌肉察觉<br> D+500<br> 现在，即使你进入了肢体妨碍毁灭状态，也可以通过回转的力量勉强行动，这意味着你即使你进入了肢体妨碍毁灭状态也可以移动，但最多只能移动等同于原移动距离一半的距离。当你对他人造成（豁免后的）肢体妨碍点数时（不包括攻击肢体造成的肢体妨碍点数），也可以选择不生效，而是改为造成等量的某一生理属性伤害。这些属性伤害在经历一次长休息后会自然消失。</p><p>Lesson3：相信回转吧！尽管相信就是了！<br> C+1000<br> 现在，当你投掷铁球时，可以选择将伤害转化为等量的肢体妨碍点数。同时，铁球强大的转劲还会对被攻击者造成二次伤害，若本次攻击造成的肢体妨碍点数还超过了对方体积，则超过的每1点肢体妨碍点数会同时带来1点流血点数，使用强韧豁免以进行对抗。</p><p>Lesson4：表达敬意吧！<br> C+1000<br> 你现在在符合并进行一次招架时，可以再消耗1点意志，一并调用下回合的标准动作，改为将手中的铁球丢出以偏转对方的攻击，进行一次不附带任何招式的攻击，你的这次检定还会额外获得等同于学习的课程数*5的检定修行加值，统计攻击检定出目，与对方的攻击检定出目比较，若你的出目大于对方的出目，则你完全无视本次攻击；若未达到，则你抵消其中的X点伤害，X为你的检定出目。无论如何，只要你应用了这个效果，将不会在本次攻击中计算你的防御，而是用这个效果代替了你的防御计算。</p><p>Lesson5：最短的捷径就是绕远路，绕远路就是我最短的捷径<br> B+2000<br> 此时，你已完全掌握了无限回转的真正奥秘。当你对某个敌人进行一次攻击时，铁球将不会再回到你的手中，而是在击中后留在他的身上疯狂转动，此后每个你的回合结束时，这颗铁球都会再造成一次你最初掷出它时造成的伤害，被击中者需要以强韧豁免进行对抗，并受到二者差值的伤害，这颗疯狂转动的铁球也可以改为应用铁球回转使用中除Lesson4以外的课程效果。若那个敌人以一次强韧豁免对抗成功铁球的伤害出目，则铁球会自然掉落，不再继续造成伤害，或者铁球击打的部位肢体妨碍毁灭，也会自然掉落。敌人也可以选择在此时用正常的标准动作来击碎铁球，无论其造成了多少伤害，都视为成功击碎这颗铁球。你最多只能同时保持一颗这样的铁球。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
